CommentText:
Clear and reset on bad sequence.

def checkInclusion(self, s1: str, s2: str) -> bool:
        PCOUNT = Counter(s1)
        
        wcount = Counter()
        left = 0
        for right in range(len(s2)):
            c = s2[right]
            if c not in PCOUNT:
                wcount.clear()
            else:
                if not wcount:
                    left = right
                
                wcount[c] += 1
                
                while wcount[c] > PCOUNT[c]:
                    wcount[s2[left]] -=1
                    left += 1
                
                if wcount[c] == PCOUNT[c] and right - left + 1 == len(s1):
                    return True
        
        return False

